$input.item.json = {
  debug: true,
  defaults: {
    invalid_route: {
      response: 'requested endpoint not available',
      status_code: 400
    }
  },
  db: {
    tables: {
      internal_label: 'physical_table_name'
    }
  },
  api_base_url: 'auto' // will be automatically extracted below
};

/*
  automatic api base url extraction
*/
if ($input.item.json.api_base_url === 'auto') {
  const full = $('_REQUEST').item.json.webhookUrl;
  const marker = '/api/v';
  const pos = full.indexOf(marker);

  if (pos === -1)
    throw new Error(`No api base url for "${marker}" in "${full}"`);

  const base = full.slice(0, pos);
  const rest = full.slice(pos + marker.length);
  const version = rest.match(/^(\d+)/)?.[1];

  $input.item.json.api_base_url = `${base}${marker}${version}`;
}
return $input.item;
